#include <bits/stdc++.h>

using namespace std;
vector < vector < int >> adj;
vector < long > toll;
long totalCost;
long dfs(int node, int parent, long k) {
    if (adj[node].size() == 1 && adj[node][0] == parent) {
        totalCost = totalCost + max((long) 0, toll[node] - k) * 2;
        return toll[node] = min(toll[node], k);
    }
    long maxChildCost = INT_MIN;
    for (auto it: adj[node]) {
        if (it != parent) {
            long childCost = dfs(it, node, k);
            if (childCost + toll[node] > k) {
                totalCost = totalCost + (childCost + toll[node] - k) * 2;
                toll[node] = k - childCost;
            }
            maxChildCost = max(maxChildCost, childCost);

        }
    }

    return maxChildCost + toll[node];
}

int solve() {
    int n, x;
    long k;
    cin >> n >> x >> k;
    adj.assign(n + 1, vector < int > ());

    toll.assign(n + 1, 0);
    totalCost = 0;
    for (int i = 1; i <= n; i++) {
        cin >> toll[i];
    }
    for (int i = 1; i < n; i++) {
        int u, v;
        cin >> u >> v;
        adj[u].push_back(v);
        adj[v].push_back(u);

    }
    int ans = dfs(x, -1, k);
    cout << totalCost << endl;
    return 0;
}
int main() {
    int t;
